#include <stdio.h>
#include <stdbool.h>

#define MAX_MEMORY 1000

typedef struct {
    int start;
    int size;
    bool allocated;
    int process_id;
} MemoryBlock;

MemoryBlock memory[MAX_MEMORY];
int num_blocks = 0;

void initialize_memory() {
    memory[0].start = 0;
    memory[0].size = MAX_MEMORY;
    memory[0].allocated = false;
    memory[0].process_id = -1;
    num_blocks = 1;
}

int first_fit(int process_id, int size) {
    for (int i = 0; i < num_blocks; i++) {
        if (!memory[i].allocated && memory[i].size >= size) {
            // Found suitable block
            if (memory[i].size > size) {
                // Split block
                memory[num_blocks].start = memory[i].start + size;
                memory[num_blocks].size = memory[i].size - size;
                memory[num_blocks].allocated = false;
                memory[num_blocks].process_id = -1;
                num_blocks++;
            }
            memory[i].allocated = true;
            memory[i].process_id = process_id;
            memory[i].size = size;
            return memory[i].start;
        }
    }
    return -1; // No suitable block found
}

void deallocate(int process_id) {
    for (int i = 0; i < num_blocks; i++) {
        if (memory[i].allocated && memory[i].process_id == process_id) {
            memory[i].allocated = false;
            memory[i].process_id = -1;
            // Merge with adjacent free blocks
            // (simplified - would need full coalescing logic)
            break;
        }
    }
}

int main() {
    initialize_memory();
    int addr1 = first_fit(1, 200);
    int addr2 = first_fit(2, 300);
    int addr3 = first_fit(3, 150);

    printf("Process 1 allocated at: %d\n", addr1);
    printf("Process 2 allocated at: %d\n", addr2);
    printf("Process 3 allocated at: %d\n", addr3);

    return 0;
}
